INSERT INTO `modx_usertest_variants` (`id`, `test_id`, `start_point`, `end_point`, `result`) VALUES (3, 1, 0, 15, 'Число баллов менее 16 говорит о том, что у вас серьезные проблемы с воспитанием ребенка. Вам недостает либо знаний, либо желания и стремления сделать ребенка личностью, а возможно, и того и другого.');
INSERT INTO `modx_usertest_variants` (`id`, `test_id`, `start_point`, `end_point`, `result`) VALUES (4, 1, 16, 30, 'Сумма от 16 до 30 баллов: забота о ребенке для вас вопрос первостепенной важности. Вы обладаете способностями воспитателя, но на практике не всегда применяете их последовательно и целенаправленно. Порой вы чересчур строги, в других случаях - излишне мягки, кроме того, вы склонны к компромиссам, которые ослабляют воспитательный эффект. Вам следует серьезно задуматься над своим подходом к воспитанию ребенка.');
INSERT INTO `modx_usertest_variants` (`id`, `test_id`, `start_point`, `end_point`, `result`) VALUES (5, 1, 31, 78, 'Если вы набрали от 30 до 39 баллов, это значит, что ребенок - самая большая ценность в вашей жизни. Вы стремитесь не только понять, но и узнать его, относитесь к нему с уважением, придерживаетесь наиболее прогрессивных принципов воспитания и постоянной линии поведения. Другими словами, вы действуете правильно и можете надеяться на хорошие результаты.');
